import { ConfirmationModal } from '@/pages/RestoreFromBackup/ConfirmationModal';
import { CrossClusterRestoreData } from '@/pages/RestoreFromBackup/CrossClusterForm';
import { RestoreMode } from '@/pages/RestoreFromBackup/helpers';
import { RestoreModeAccordion } from '@/pages/RestoreFromBackup/RestoreModeAccordion';
import { SameClusterRestoreData } from '@/pages/RestoreFromBackup/SameClusterForm';
import { buildWorkspacesLocation } from '@/services/helpers/location';
import { AppDispatch, RootState } from '@/store';
import { fetchBackupList, validateBackupImage } from '@/store/Backups/actions';
import { selectNamespaceBackups } from '@/store/Backups/selectors';
import { selectDefaultNamespace } from '@/store/InfrastructureNamespaces/selectors';
import { selectDefaultEditor } from '@/store/ServerConfig/selectors';
import { workspacesActionCreators } from '@/store/Workspaces';

type MappedProps = ConnectedProps<typeof connector>;

type Props = MappedProps & {
  navigate: NavigateFunction;
  initialBackupImageUrl?: string;
};

type State = {
  editorDefinition: string | undefined;
  editorImage: string | undefined;
  restoreMode: RestoreMode;
  isConfirmModalOpen: boolean;
  isSubmitting: boolean;
  submitError: string;
  restoreData: SameClusterRestoreData | CrossClusterRestoreData | null;
  isFormValid: boolean;
};

export class RestoreFromBackupPage extends React.PureComponent<Props, State> {
  constructor(props: Props) {
    super(props);

    const hasInitialImage = !!props.initialBackupImageUrl;

    this.state = {
      editorDefinition: undefined,
      editorImage: undefined,
      restoreMode: hasInitialImage ? 'cross-cluster' : 'same-cluster',
      isConfirmModalOpen: false,
      isSubmitting: false,
      submitError: '',
      restoreData: null,
      isFormValid: false,
    };
  }

  private handleEditorSelect(
    editorDefinition: string | undefined,
    editorImage: string | undefined,
  ): void {
    this.setState({ editorDefinition, editorImage });
  }

  public componentDidMount(): void {
    const { defaultNamespace } = this.props;
    const namespace = defaultNamespace.name;
    if (namespace) {
      this.props.fetchBackupList({ namespace });
    }
  }

  private handleModeChange(mode: RestoreMode): void {
    this.setState({
      restoreMode: mode,
      restoreData: null,
      isFormValid: false,
    });
  }

  private handleSameClusterValidationChange(
    isValid: boolean,
    data: SameClusterRestoreData | null,
  ): void {
    this.setState({ isFormValid: isValid, restoreData: data });
  }

  private handleCrossClusterValidationChange(
    isValid: boolean,
    data: CrossClusterRestoreData | null,
  ): void {
    this.setState({ isFormValid: isValid, restoreData: data });
  }

  private async handleValidateImage(imageUrl: string): Promise<BackupValidationResult> {
    const { defaultNamespace } = this.props;
    const namespace = defaultNamespace.name || 'default';
    const result = await this.props.validateBackupImage({ namespace, imageUrl });
    return unwrapResult(result);
  }

  private handleRestoreClick(): void {
    this.setState({ isConfirmModalOpen: true });
  }

  private handleConfirmCancel(): void {
    this.setState({ isConfirmModalOpen: false });
  }

  private async handleConfirmRestore(): Promise<void> {
    this.setState({ isConfirmModalOpen: false, isSubmitting: true, submitError: '' });

    try {
      const { restoreData } = this.state;
      if (!restoreData) {
        throw new Error('No restore data available');
      }

      const { workspaceName, imageUrl } = restoreData;
      const { defaultNamespace, defaultEditor } = this.props;
      const namespace = defaultNamespace.name;
      const { editorDefinition } = this.state;
      const resolvedEditorId = editorDefinition ?? defaultEditor;

      await this.props.restoreFromBackup(namespace, workspaceName, imageUrl, resolvedEditorId);

      const location = buildWorkspacesLocation();
      this.props.navigate(location);
    } catch (e: unknown) {
      const errorMessage = e instanceof Error ? e.message : 'Failed to initiate restore.';
      this.setState({ isSubmitting: false, submitError: errorMessage });
    }
  }

  private handleCancel(): void {
    const location = buildWorkspacesLocation();
    this.props.navigate(location);
  }

  public render(): React.ReactElement {
    const { restoreMode, isConfirmModalOpen, isSubmitting, submitError, isFormValid, restoreData } =
      this.state;

    const actionButton = (
      <React.Fragment>
        <Button
          variant={ButtonVariant.primary}
          isDisabled={!isFormValid || isSubmitting}
          isLoading={isSubmitting}
          onClick={() => this.handleRestoreClick()}
          data-testid="restore-submit-button"
        >
          Restore Workspace
        </Button>
        <Button
          variant={ButtonVariant.link}
          isDisabled={isSubmitting}
          onClick={() => this.handleCancel()}
          data-testid="restore-cancel-button"
        >
          Cancel
        </Button>
      </React.Fragment>
    );

    return (
      <React.Fragment>
        <Head pageName="Restore from Backup" />

        <PageSection variant={PageSectionVariants.light}>
          <Title headingLevel="h1">Restore from Backup</Title>
        </PageSection>

        <Divider />

        <PageSection variant={PageSectionVariants.default}>
          <EditorSelector
            defaultEditorId={this.props.defaultEditor}
            onSelect={(editorDefinition, editorImage) =>
              this.handleEditorSelect(editorDefinition, editorImage)
            }
          />

          <Spacer />

          {submitError && (
            <Alert
              variant={AlertVariant.danger}
              title="Restore failed"
              isInline
              data-testid="restore-error-alert"
            >
              {submitError}
            </Alert>
          )}

          {/* <div className={styles.restoreForm} data-testid="restore-from-backup-page"> */}
          <div data-testid="restore-from-backup-page">
            <RestoreModeAccordion
              restoreMode={restoreMode}
              onChange={mode => this.handleModeChange(mode)}
              backups={this.props.backups}
              onSameClusterValidationChange={(isValid, data) =>
                this.handleSameClusterValidationChange(isValid, data)
              }
              initialImageUrl={this.props.initialBackupImageUrl}
              onValidateImage={imageUrl => this.handleValidateImage(imageUrl)}
              onCrossClusterValidationChange={(isValid, data) =>
                this.handleCrossClusterValidationChange(isValid, data)
              }
              actionButton={actionButton}
            />
          </div>
        </PageSection>

        {restoreData && (
          <ConfirmationModal
            isOpen={isConfirmModalOpen}
            restoreMode={restoreMode}
            workspaceName={restoreData.workspaceName}
            imageUrl={restoreData.imageUrl}
            onConfirm={() => this.handleConfirmRestore()}
            onCancel={() => this.handleConfirmCancel()}
          />
        )}
      </React.Fragment>
    );
  }
}

const mapStateToProps = (state: RootState) => {
  const defaultNamespace = selectDefaultNamespace(state);
  const namespace = defaultNamespace.name;
  return {
    defaultNamespace,
    backups: selectNamespaceBackups(state, namespace),
    defaultEditor: selectDefaultEditor(state),
  };
};

const mapDispatchToProps = (dispatch: AppDispatch) => ({
  validateBackupImage: (params: { namespace: string; imageUrl: string }) =>
    dispatch(validateBackupImage(params)),
  fetchBackupList: (params: { namespace: string }) => dispatch(fetchBackupList(params)),
  restoreFromBackup: (
    namespace: string,
    workspaceName: string,
    backupImageUrl: string,
    editorId: string,
  ) =>
    dispatch(
      workspacesActionCreators.restoreFromBackup(
        namespace,
        workspaceName,
        backupImageUrl,
        editorId,
      ),
    ),
});

const connector = connect(mapStateToProps, mapDispatchToProps);

export default connector(RestoreFromBackupPage);
